@startuml
skinparam classAttributeIconSize 0

class AssignProductOwnerUI {
}

class AssignProductOwnerController {
    +AssignProductOwnerController()
    +getProject(code)
    +getResource(name)
    +assignRole(resourceName, roleName)
}

class ProjectsMapper {
    +toDTO(project)
}

class ProjectTeamMapper {
    +toDto(resource)
}

class Company {
    +Company()
    +getProjectStore()
    +getProjectRoleStore()
}

class ProjectStore {
    +ProjectStore()
    +getProjectByCode()
}

class ProjectRoleStore {
    +ProjectRoleStore()
    +getProjectRole(roleName)
}

class Resource {
    +Resource()
    +Resource(originalResource)
    +isYourName(name)
    +isCurrent()
    +setRole(role)
    +setStartDate(startDate)
    +setEndDate(startDate)
    +isAvailableToSprint(startDate, sprintDuration)
    +copyUpdateProjectRoleOfAResource(originalResource, startDateNewRole, role)
}

class SprintList {
    +SprintList()
    +getCurrentSprint()
}

class Sprint {
    +Sprint()
    +isCurrentSprint()
    +getEndDate()
}

interface IHasProjectsAndRoles {
}

abstract class AbstractEntity<T> {
}

enum RoleType {
    PRODUCT_OWNER
}

' Relationships from UI to Controller
AssignProductOwnerUI ..> AssignProductOwnerController : >

' Dependencies of Controller on Mappers and Stores/Entities via dashed lines
AssignProductOwnerController .left.> ProjectsMapper
AssignProductOwnerController .right.> ProjectTeamMapper
AssignProductOwnerController --> Company
AssignProductOwnerController -down-> Resource
AssignProductOwnerController --( Project ) 

